<script setup lang="ts">
import { ref, onMounted, onBeforeUnmount } from 'vue'
import { useHomeStore } from '@/stores/home'

const store = useHomeStore()
const paused = ref(false)

// 双倍内容拼接实现无缝循环
const doubled = [...store.bannerMessages, ...store.bannerMessages]
let timer: ReturnType<typeof setInterval> | null = null

onMounted(() => {
  // 4s 切换一条(整体左移一份宽度)
  timer = setInterval(() => {
    if (paused.value) return
    const track = document.getElementById('marquee-track')
    if (!track) return
    track.appendChild(track.firstElementChild as HTMLElement)
  }, 4000)
})

onBeforeUnmount(() => {
  if (timer) clearInterval(timer)
})
</script>

<template>
  <div
    class="absolute top-12 left-0 right-0 z-20 h-9 flex items-center justify-center bg-black/60 border-y border-amber-700/40"
    @mouseenter="paused = true"
    @mouseleave="paused = false"
  >
    <span class="text-amber-300 text-[14px] font-bold tracking-wider drop-shadow">
      {{ store.bannerSubtitle }}
    </span>
    <div class="absolute left-0 right-0 top-full h-7 overflow-hidden pointer-events-none">
      <div
        id="marquee-track"
        class="marquee-track flex items-center h-full"
        :class="{ 'motion-reduce:animate-none': true }"
      >
        <span
          v-for="(msg, i) in doubled"
          :key="i"
          class="marquee-item shrink-0 px-8 text-[12px] text-amber-100 whitespace-nowrap"
        >
          ✦ {{ msg }}
        </span>
      </div>
    </div>
  </div>
</template>
