/**
 * 助战 / 万象 弹框的开关状态(单例)
 * 跟 useRolePanel 一样的模式:模块级 ref,跨组件共享 isOpen
 * 内容待定,先搭好框架
 */
import { ref } from 'vue';
const assistOpen = ref(false);
const wanxiangOpen = ref(false);
export function useFeaturePanels() {
    return {
        assistOpen,
        wanxiangOpen,
        openAssist: () => {
            assistOpen.value = true;
        },
        openWanxiang: () => {
            wanxiangOpen.value = true;
        },
        closeAssist: () => {
            assistOpen.value = false;
        },
        closeWanxiang: () => {
            wanxiangOpen.value = false;
        },
    };
}
