<script setup lang="ts">
import { computed, withDefaults } from 'vue'

/**
 * 统一资源引用:把 "assets/xxx" 或 "bg/xxx" 解析为 /assets/xxx
 * 走 Vite public 目录,不参与 bundle
 */
const props = withDefaults(
  defineProps<{
    src: string
    alt?: string
    width?: string | number
    height?: string | number
  }>(),
  { alt: '', width: undefined, height: undefined },
)

const resolved = computed(() => {
  if (!props.src) return ''
  if (props.src.startsWith('http') || props.src.startsWith('/')) return props.src
  return `/assets/${props.src.replace(/^\/+/, '')}`
})
</script>

<template>
  <img
    :src="resolved"
    :alt="alt"
    :width="'100%'"
    :height="'100%'"
    loading="lazy"
    decoding="async"
    draggable="false"
  />
</template>
