<script setup lang="ts">
import { computed } from 'vue'
import { useRoute, useRouter, type RouteLocationRaw } from 'vue-router'
import AssetImg from '@/components/common/AssetImg.vue'
import IconBadge from '@/components/common/IconBadge.vue'
import { useHomeStore } from '@/stores/home'
import { useFeaturePanels } from '@/composables/useFeaturePanels'

interface TabItem {
  key: string
  label: string
  /** 按钮图标 PNG 文件名(不带后缀,在 /assets/bg/ 下) */
  icon: string
  to: RouteLocationRaw
  hasRedDot?: boolean
  /** 如果设置,点击改为打开对应弹框(不跳路由);否则按 to 跳转 */
  openPanel?: 'assist' | 'wanxiang'
}

const router = useRouter()
const route = useRoute()
const store = useHomeStore()
const panels = useFeaturePanels()

/** 7 个底部 tab,顺序:角色 / 装备 / 助战 / 社交 / 背包 / 排行榜 / 万象
 *  图标文件是拼音缩写,都在 public/assets/bg/ 下
 *
 *  助战 / 万象 通过 openPanel 打开弹框(不走路由)
 *  其他 5 个用 path 跳转(避开 named match 边缘 case) */
const tabs: TabItem[] = [
  { key: 'role', label: '角色', icon: 'js', to: '/role', hasRedDot: true },
  { key: 'equipment', label: '装备', icon: 'zb', to: '/equipment' },
  { key: 'assist', label: '助战', icon: 'zz', to: '/assist', openPanel: 'assist' },
  { key: 'social', label: '社交', icon: 'sj', to: '/social' },
  { key: 'inventory', label: '背包', icon: 'bb', to: '/inventory' },
  { key: 'rank', label: '排行榜', icon: 'phb', to: '/rank' },
  { key: 'wanxiang', label: '万象', icon: 'wx', to: '/wanxiang', openPanel: 'wanxiang' },
]

const activeKey = computed(() => {
  const match = tabs.find((t) => t.key === route.name)
  return match?.key ?? tabs[0].key
})

function onClick(t: TabItem) {
  // 1) 助战 / 万象:打开对应弹框
  if (t.openPanel === 'assist') {
    panels.openAssist()
    return
  }
  if (t.openPanel === 'wanxiang') {
    panels.openWanxiang()
    return
  }
  // 2) 其他:正常路由跳转
  if (route.name === t.key) return
  store.setTab(t.key as any)
  router.push(t.to)
}
</script>

<template>
  <div
    class="absolute bottom-0 left-0 right-0 z-30 h-20 flex items-end justify-center gap-1 px-4 pb-2 bg-gradient-to-t from-black/85 to-transparent"
  >
    <button
      v-for="t in tabs"
      :key="t.key"
      class="relative flex flex-col items-center justify-center w-16 h-16 rounded-t-xl transition-transform"
      :class="[
        activeKey === t.key
          ? 'bg-gradient-to-b from-amber-500 to-amber-800 text-white shadow-btn-gold -translate-y-1'
          : 'bg-black/60 text-amber-100 hover:bg-black/80',
      ]"
      @click="onClick(t)"
    >
      <AssetImg :src="`bg/${t.icon}.png`" :alt="t.label" class="w-8 h-8 object-contain" />
      <span class="text-[12px] mt-0.5 font-bold">{{ t.label }}</span>
      <IconBadge v-if="t.key === 'role' && store.unreadMail > 0" :count="store.unreadMail" />
    </button>
  </div>
</template>
