<script setup lang="ts">
import { withDefaults } from 'vue'

/**
 * 通用红点徽标
 * - 同时传 count 和 dot 时,显示数字优先
 * - count<=0 且无 dot 不渲染
 */
withDefaults(
  defineProps<{
    count?: number
    dot?: boolean
    max?: number
  }>(),
  { count: 0, dot: false, max: 99 },
)

const display = (n: number, max: number) => (n > max ? `${max}+` : String(n))
</script>

<template>
  <span
    v-if="count > 0 || dot"
    class="absolute -top-1 -right-1 min-w-[18px] h-[18px] px-1 rounded-full bg-home-red text-white text-[10px] font-bold flex items-center justify-center shadow-md ring-2 ring-black/40 pointer-events-none"
  >
    <template v-if="count > 0">{{ display(count, max) }}</template>
    <template v-else>&nbsp;</template>
  </span>
</template>
